import React, { useState, useEffect } from 'react';
import { ethers } from 'ethers';
import { Activity, Thermometer, Droplets, MapPin, AlertTriangle, CheckCircle, Clock } from 'lucide-react';
import { ReefMonitorABI } from '../contracts/abis';
import { CONTRACTS } from '../contracts/addresses';

interface ReefData {
  reefId: string;
  location: string;
  healthScore: number;
  temperature: bigint;
  phLevel: bigint;
  coralCoverage: number;
  speciesDetected: string[];
  imageHash: string;
  timestamp: bigint;
  reporter: string;
  source: number;
}

interface ReefHealthDashboardProps {
  connectedAddress?: string;
  chainId?: number;
}

const ReefHealthDashboard: React.FC<ReefHealthDashboardProps> = ({ chainId }) => {
  const [reefs, setReefs] = useState<ReefData[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedReef, setSelectedReef] = useState<ReefData | null>(null);
  const [stats, setStats] = useState({
    total: 0,
    critical: 0,
    poor: 0,
    fair: 0,
    good: 0,
    excellent: 0,
  });

  useEffect(() => {
    loadReefData();
  }, [chainId]);

  const loadReefData = async () => {
    if (!chainId || !CONTRACTS[chainId as keyof typeof CONTRACTS]) {
      // Load mock data for demo
      loadMockData();
      return;
    }

    try {
      setLoading(true);
      const provider = new ethers.JsonRpcProvider('https://sepolia.base.org');
      const contractAddress = CONTRACTS[chainId as keyof typeof CONTRACTS]?.ReefMonitor;
      
      if (!contractAddress) {
        loadMockData();
        return;
      }

      const contract = new ethers.Contract(contractAddress, ReefMonitorABI, provider);
      const reefIds = await contract.getAllReefIds();
      
      const reefDataPromises = reefIds.map(async (id: string) => {
        const data = await contract.getLatestReefData(id);
        return data;
      });

      const reefData = await Promise.all(reefDataPromises);
      setReefs(reefData);
      calculateStats(reefData);
    } catch (err) {
      console.error('Failed to load reef data:', err);
      loadMockData();
    } finally {
      setLoading(false);
    }
  };

  const loadMockData = () => {
    const mockReefs: ReefData[] = [
      {
        reefId: 'GBR-001',
        location: 'Great Barrier Reef, Australia',
        healthScore: 72,
        temperature: BigInt(2650),
        phLevel: BigInt(805),
        coralCoverage: 65,
        speciesDetected: ['Acropora', 'Montipora', 'Clownfish', 'Sea Turtle'],
        imageHash: 'ipfs://QmReef1',
        timestamp: BigInt(Date.now() / 1000 - 3600),
        reporter: '0x1234...',
        source: 0,
      },
      {
        reefId: 'MAL-001',
        location: 'Maldives Atoll',
        healthScore: 45,
        temperature: BigInt(2800),
        phLevel: BigInt(780),
        coralCoverage: 35,
        speciesDetected: ['Porites', 'Parrotfish'],
        imageHash: 'ipfs://QmReef2',
        timestamp: BigInt(Date.now() / 1000 - 7200),
        reporter: '0x5678...',
        source: 1,
      },
      {
        reefId: 'CAR-001',
        location: 'Caribbean Reef, Belize',
        healthScore: 88,
        temperature: BigInt(2700),
        phLevel: BigInt(820),
        coralCoverage: 82,
        speciesDetected: ['Elkhorn Coral', 'Brain Coral', 'Nurse Shark', 'Stingray'],
        imageHash: 'ipfs://QmReef3',
        timestamp: BigInt(Date.now() / 1000 - 1800),
        reporter: '0x9012...',
        source: 2,
      },
      {
        reefId: 'RED-001',
        location: 'Red Sea, Egypt',
        healthScore: 15,
        temperature: BigInt(2950),
        phLevel: BigInt(750),
        coralCoverage: 12,
        speciesDetected: ['Bleached Coral'],
        imageHash: 'ipfs://QmReef4',
        timestamp: BigInt(Date.now() / 1000 - 5400),
        reporter: '0x3456...',
        source: 0,
      },
      {
        reefId: 'PHI-001',
        location: 'Palawan, Philippines',
        healthScore: 62,
        temperature: BigInt(2750),
        phLevel: BigInt(795),
        coralCoverage: 58,
        speciesDetected: ['Table Coral', 'Moorish Idol', 'Butterflyfish'],
        imageHash: 'ipfs://QmReef5',
        timestamp: BigInt(Date.now() / 1000 - 9000),
        reporter: '0x7890...',
        source: 3,
      },
    ];
    setReefs(mockReefs);
    calculateStats(mockReefs);
    setLoading(false);
  };

  const calculateStats = (reefData: ReefData[]) => {
    const newStats = {
      total: reefData.length,
      critical: 0,
      poor: 0,
      fair: 0,
      good: 0,
      excellent: 0,
    };

    reefData.forEach(reef => {
      if (reef.healthScore < 20) newStats.critical++;
      else if (reef.healthScore < 40) newStats.poor++;
      else if (reef.healthScore < 60) newStats.fair++;
      else if (reef.healthScore < 80) newStats.good++;
      else newStats.excellent++;
    });

    setStats(newStats);
  };

  const getHealthStatus = (score: number) => {
    if (score < 20) return { label: 'Critical', class: 'health-critical', color: 'text-red-400' };
    if (score < 40) return { label: 'Poor', class: 'health-poor', color: 'text-orange-400' };
    if (score < 60) return { label: 'Fair', class: 'health-fair', color: 'text-yellow-400' };
    if (score < 80) return { label: 'Good', class: 'health-good', color: 'text-green-400' };
    return { label: 'Excellent', class: 'health-excellent', color: 'text-cyan-400' };
  };

  const getSourceIcon = (source: number) => {
    const sources = ['Sensor', 'Satellite', 'Diver Report', 'AI Analysis'];
    return sources[source] || 'Unknown';
  };

  const formatTime = (timestamp: bigint) => {
    const date = new Date(Number(timestamp) * 1000);
    const hours = Math.floor((Date.now() - date.getTime()) / (1000 * 60 * 60));
    if (hours < 1) return 'Just now';
    if (hours < 24) return `${hours}h ago`;
    return `${Math.floor(hours / 24)}d ago`;
  };

  if (loading) {
    return (
      <section id="dashboard" className="pt-32 pb-20 px-4">
        <div className="max-w-7xl mx-auto text-center">
          <div className="loading-wave text-white">
            {[...Array(5)].map((_, i) => <div key={i} />)}
          </div>
          <p className="mt-4 text-white/60">Loading reef data...</p>
        </div>
      </section>
    );
  }

  return (
    <section id="dashboard" className="pt-32 pb-20 px-4">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="text-center mb-12">
          <h2 className="text-4xl md:text-5xl font-bold mb-4">
            Reef <span className="text-ocean-gradient">Health Dashboard</span>
          </h2>
          <p className="text-lg text-white/70 max-w-2xl mx-auto">
            Real-time monitoring of coral reef ecosystems worldwide. AI-powered insights combined with on-chain verification for transparent conservation data.
          </p>
        </div>

        {/* Stats Overview */}
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4 mb-12">
          {[
            { label: 'Total Reefs', value: stats.total, icon: Activity, color: 'text-white' },
            { label: 'Critical', value: stats.critical, icon: AlertTriangle, color: 'text-red-400' },
            { label: 'Poor', value: stats.poor, icon: AlertTriangle, color: 'text-orange-400' },
            { label: 'Fair', value: stats.fair, icon: Clock, color: 'text-yellow-400' },
            { label: 'Good', value: stats.good, icon: CheckCircle, color: 'text-green-400' },
            { label: 'Excellent', value: stats.excellent, icon: CheckCircle, color: 'text-cyan-400' },
          ].map((stat, index) => (
            <div key={index} className="ocean-card text-center p-4">
              <stat.icon className={`w-6 h-6 mx-auto mb-2 ${stat.color}`} />
              <p className="text-2xl font-bold">{stat.value}</p>
              <p className="text-xs text-white/60">{stat.label}</p>
            </div>
          ))}
        </div>

        {/* Reef Grid */}
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
          {reefs.map((reef, index) => {
            const health = getHealthStatus(reef.healthScore);
            return (
              <div
                key={reef.reefId}
                onClick={() => setSelectedReef(reef)}
                className="ocean-card cursor-pointer transform transition-all duration-300 hover:scale-105 hover:shadow-2xl"
                style={{ animationDelay: `${index * 100}ms` }}
              >
                {/* Header */}
                <div className="flex items-start justify-between mb-4">
                  <div>
                    <h3 className="font-semibold text-lg">{reef.reefId}</h3>
                    <div className="flex items-center gap-1 text-sm text-white/60">
                      <MapPin className="w-3 h-3" />
                      {reef.location}
                    </div>
                  </div>
                  <span className={`px-3 py-1 rounded-full text-xs font-medium bg-white/10 ${health.color}`}>
                    {health.label}
                  </span>
                </div>

                {/* Health Bar */}
                <div className="mb-4">
                  <div className="flex justify-between text-sm mb-1">
                    <span>Health Score</span>
                    <span className="font-bold">{reef.healthScore}/100</span>
                  </div>
                  <div className="health-bar">
                    <div
                      className={`health-fill ${health.class}`}
                      style={{ width: `${reef.healthScore}%` }}
                    />
                  </div>
                </div>

                {/* Metrics */}
                <div className="grid grid-cols-3 gap-3 mb-4">
                  <div className="bg-white/5 rounded-lg p-2 text-center">
                    <Thermometer className="w-4 h-4 mx-auto mb-1 text-orange-400" />
                    <p className="text-xs text-white/60">Temp</p>
                    <p className="text-sm font-medium">{(Number(reef.temperature) / 100).toFixed(1)}°C</p>
                  </div>
                  <div className="bg-white/5 rounded-lg p-2 text-center">
                    <Droplets className="w-4 h-4 mx-auto mb-1 text-blue-400" />
                    <p className="text-xs text-white/60">pH</p>
                    <p className="text-sm font-medium">{(Number(reef.phLevel) / 100).toFixed(1)}</p>
                  </div>
                  <div className="bg-white/5 rounded-lg p-2 text-center">
                    <Activity className="w-4 h-4 mx-auto mb-1 text-reef-400" />
                    <p className="text-xs text-white/60">Coral</p>
                    <p className="text-sm font-medium">{reef.coralCoverage}%</p>
                  </div>
                </div>

                {/* Footer */}
                <div className="flex items-center justify-between text-xs text-white/50">
                  <span>Source: {getSourceIcon(reef.source)}</span>
                  <span className="flex items-center gap-1">
                    <Clock className="w-3 h-3" />
                    {formatTime(reef.timestamp)}
                  </span>
                </div>
              </div>
            );
          })}
        </div>

        {/* Reef Detail Modal */}
        {selectedReef && (
          <div 
            className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm"
            onClick={() => setSelectedReef(null)}
          >
            <div 
              className="ocean-card max-w-2xl w-full max-h-[90vh] overflow-y-auto"
              onClick={e => e.stopPropagation()}
            >
              <div className="flex items-start justify-between mb-6">
                <div>
                  <h3 className="text-2xl font-bold">{selectedReef.reefId}</h3>
                  <div className="flex items-center gap-2 text-white/60 mt-1">
                    <MapPin className="w-4 h-4" />
                    {selectedReef.location}
                  </div>
                </div>
                <button
                  onClick={() => setSelectedReef(null)}
                  className="p-2 rounded-lg bg-white/10 hover:bg-white/20 transition-colors"
                >
                  ×
                </button>
              </div>

              {/* Health Score */}
              <div className="mb-6">
                <div className="flex items-center gap-4 mb-2">
                  <span className="text-lg">Health Score:</span>
                  <span className={`text-3xl font-bold ${getHealthStatus(selectedReef.healthScore).color}`}>
                    {selectedReef.healthScore}/100
                  </span>
                </div>
                <div className="health-bar h-4">
                  <div
                    className={`health-fill ${getHealthStatus(selectedReef.healthScore).class}`}
                    style={{ width: `${selectedReef.healthScore}%` }}
                  />
                </div>
              </div>

              {/* Species */}
              <div className="mb-6">
                <h4 className="text-lg font-semibold mb-3">Detected Species</h4>
                <div className="flex flex-wrap gap-2">
                  {selectedReef.speciesDetected.map((species, idx) => (
                    <span
                      key={idx}
                      className="px-3 py-1 rounded-full bg-reef-500/20 text-reef-300 text-sm border border-reef-500/30"
                    >
                      {species}
                    </span>
                  ))}
                </div>
              </div>

              {/* Details Grid */}
              <div className="grid grid-cols-2 gap-4">
                <div className="bg-white/5 rounded-xl p-4">
                  <p className="text-white/60 text-sm">Temperature</p>
                  <p className="text-2xl font-bold">{(Number(selectedReef.temperature) / 100).toFixed(1)}°C</p>
                </div>
                <div className="bg-white/5 rounded-xl p-4">
                  <p className="text-white/60 text-sm">pH Level</p>
                  <p className="text-2xl font-bold">{(Number(selectedReef.phLevel) / 100).toFixed(2)}</p>
                </div>
                <div className="bg-white/5 rounded-xl p-4">
                  <p className="text-white/60 text-sm">Coral Coverage</p>
                  <p className="text-2xl font-bold">{selectedReef.coralCoverage}%</p>
                </div>
                <div className="bg-white/5 rounded-xl p-4">
                  <p className="text-white/60 text-sm">Data Source</p>
                  <p className="text-2xl font-bold">{getSourceIcon(selectedReef.source)}</p>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </section>
  );
};

export default ReefHealthDashboard;
